import React, { useState, useEffect } from 'react';

import api from '../api';

const OrderPage = () => {
  const [foods, setFoods] = useState([]);
  const [orderItems, setOrderItems] = useState([]);
  const [orderPlaced, setOrderPlaced] = useState(null);
  const [loading, setLoading] = useState(false);


  useEffect(() => {
    const fetchFoods = async () => {
      try {
        const res = await api.get('/foods'); // Update if different endpoint
        setFoods(res.data);
      } catch (err) {
        console.error('Failed to fetch food items');
      }
    };
    fetchFoods();
  }, []);

  const addToOrder = (food) => {
    const existing = orderItems.find(item => item.food._id === food._id);
    if (existing) {
      setOrderItems(orderItems.map(item =>
        item.food._id === food._id
          ? { ...item, quantity: item.quantity + 1 }
          : item
      ));
    } else {
      setOrderItems([...orderItems, { food, quantity: 1 }]);
    }
  };

  const removeItem = (id) => {
    setOrderItems(orderItems.filter(item => item.food._id !== id));
  };

  const submitOrder = async () => {
    setLoading(true);
    try {
      const payload = orderItems.map(({ food, quantity }) => ({
        food: food.id,
        quantity,
        price: food.price, // Important
      }));

      const res = await api.post('/orders/order', { items: payload });
      setOrderPlaced(res.data);
      setOrderItems([]);
    } catch (err) {
      console.error('Error placing order:', err);
      alert('Something went wrong');
    }
    setLoading(false);
  };

  const totalPrice = orderItems.reduce((sum, item) => sum + item.food.price * item.quantity, 0);

  return (
    <div className="container mt-5">
      <h2 className="mb-4">🍽️ Place Your Order</h2>

      {!orderPlaced ? (
        <>
          <div className="row">
            {foods.map(food => (
              <div className="col-md-4 mb-3" key={food._id}>
                <div className="card h-100">
                  <div className="card-body">
                    <h5 className="card-title">{food.name}</h5>
                    <p className="card-text">₹{food.price}</p>
                    <button className="btn btn-primary" onClick={() => addToOrder(food)}>
                      Add to Order
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>

          <hr />
          <h4>Your Order</h4>
          {orderItems.length === 0 ? (
            <p>No items selected yet.</p>
          ) : (
            <>
              <ul className="list-group mb-3">
                {orderItems.map(item => (
                  <li className="list-group-item d-flex justify-content-between align-items-center" key={item.food._id}>
                    <div>
                      {item.food.name} x {item.quantity}
                    </div>
                    <div>
                      ₹{item.food.price * item.quantity}
                      <button className="btn btn-sm btn-danger ms-2" onClick={() => removeItem(item.food._id)}>
                        Remove
                      </button>
                    </div>
                  </li>
                ))}
              </ul>
              <h5>Total: ₹{totalPrice}</h5>
              <button className="btn btn-success" onClick={submitOrder} disabled={loading}>
                {loading ? 'Placing Order...' : 'Submit Order'}
              </button>
            </>
          )}
        </>
      ) : (
        <div className="alert alert-success">
          ✅ Order placed successfully! <br />
          <strong>Order Token:</strong> {orderPlaced.token} <br />
          <strong>Total:</strong> ₹{orderPlaced.totalPrice}
        </div>
      )}
    </div>
  );
};

export default OrderPage;
